oxy_webhelp_navlinks = {"oracle_live_mount-d30753e32765":{"topics":[{"title":"Directories created before a recovery operation","shortdesc":"<p class=\"shortdesc\">The Rubrik cluster automatically attempts to create common directories before an         Oracle database recovery operation.<\/p>","href":"oracle\/directories_created_before_recov_op.html","attributes":{"data-id":"directories_created_before_recov_op"},"menu":{"hasChildren":false},"tocID":"directories_created_before_recov_op-d30753e32776","topics":[]},{"title":"Live mount prerequisites","shortdesc":"<p class=\"shortdesc\">Before performing a live mount using an Oracle database snapshot, ensure the target         host meets prerequisites such as removing stale backup files, having sufficient memory,         assigning restore permissions, and ensuring unique SIDs.<\/p>","href":"oracle\/live_mount_prerequisites.html","attributes":{"data-id":"live_mount_prerequisites"},"menu":{"hasChildren":false},"tocID":"live_mount_prerequisites-d30753e32787","topics":[]},{"title":"Oracle version 11g Live Mount limitations","shortdesc":"<p class=\"shortdesc\">Due to a limitation in Oracle version 11g, <span class=\"ph\">RSC<\/span> issues an error when         you perform a Live Mount with Rename.<\/p>","href":"oracle\/oracle_vers_11g_lm_lmtns.html","attributes":{"data-id":"oracle_vers_11g_lm_lmtns"},"menu":{"hasChildren":false},"tocID":"oracle_vers_11g_lm_lmtns-d30753e32798","topics":[]},{"title":"Live mounting an Oracle database backup","shortdesc":"<p class=\"shortdesc\">Live mounting an Oracle database creates a database from a point-in-time copy of that         database.<\/p>","href":"oracle\/rbk_live_mounting_oracle_database_backup.html","attributes":{"data-id":"rbk_live_mounting_oracle_database_backup"},"menu":{"hasChildren":false},"tocID":"rbk_live_mounting_oracle_database_backup-d30753e32812","topics":[]},{"title":"Live mounting an Oracle RAC database backup","shortdesc":"<p class=\"shortdesc\">Live mounting an Oracle RAC database creates a database from a point-in-time copy of         that Oracle RAC database.<\/p>","href":"oracle\/live_mounting_oracle_rac_database_backup.html","attributes":{"data-id":"live_mounting_oracle_rac_database_backup"},"menu":{"hasChildren":false},"tocID":"live_mounting_oracle_rac_database_backup-d30753e32823","topics":[]},{"title":"Optional Advanced Settings parameters for Oracle Live Mounts","shortdesc":"<p class=\"shortdesc\">The Advanced Settings section for Oracle Live Mounts provides optional parameters for         customization and validation of the live mount operation.<\/p>","href":"oracle\/optional_advanced_settings_parameters_live_mount.html","attributes":{"data-id":"optional_advanced_settings_parameters_live_mount"},"menu":{"hasChildren":false},"tocID":"optional_advanced_settings_parameters_live_mount-d30753e32834","topics":[]},{"title":"Recover databases after a files-only live mount","shortdesc":"<p class=\"shortdesc\">Files-only live mounts enable DBAs to mount backup images from the Rubrik cluster to         an Oracle host or RAC, keeping datafiles on the Rubrik cluster.<\/p>","href":"oracle\/recover_db_after_files_only_live_mount.html","attributes":{"data-id":"recover_db_after_files_only_live_mount"},"menu":{"hasChildren":false},"tocID":"recover_db_after_files_only_live_mount-d30753e32845","next":"recover_db_after_files_only_live_mount-d30753e32845"},{"title":"Unmounting an Oracle Live Mount on <span class=\"ph\">RSC<\/span>","shortdesc":"<p class=\"shortdesc\">Unmount live mounted Oracle databases and mounted objects from <span class=\"ph\">RSC<\/span>.<\/p>","href":"oracle\/rbk_unmounting_oracle_live_mount.html","attributes":{"data-id":"rbk_unmounting_oracle_live_mount"},"menu":{"hasChildren":false},"tocID":"rbk_unmounting_oracle_live_mount-d30753e32900","next":"rbk_unmounting_oracle_live_mount-d30753e32900"}]}};